import torch
import torch.nn as nn
import torch.nn.functional as F
import torch.distributed as dist


def _world_size():
    if dist.is_available() and dist.is_initialized():
        return dist.get_world_size()
    return 1


def _rank():
    if dist.is_available() and dist.is_initialized():
        return dist.get_rank()
    return 0


class _AllGatherLastDim(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_):
        world_size = _world_size()
        ctx.world_size = world_size
        ctx.rank = _rank()
        if world_size == 1:
            return input_
        input_ = input_.contiguous()
        tensors = [torch.empty_like(input_) for _ in range(world_size)]
        dist.all_gather(tensors, input_)
        return torch.cat(tensors, dim=-1)

    @staticmethod
    def backward(ctx, grad_output):
        world_size = ctx.world_size
        if world_size == 1:
            return grad_output
        chunk = grad_output.shape[-1] // world_size
        rank = ctx.rank
        grad = grad_output[..., rank * chunk:(rank + 1) * chunk]
        return grad.contiguous()


class _AllReduce(torch.autograd.Function):
    @staticmethod
    def forward(ctx, input_):
        if _world_size() == 1:
            return input_
        out = input_.clone()
        dist.all_reduce(out)
        return out

    @staticmethod
    def backward(ctx, grad_output):
        return grad_output


class ColumnParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        world_size = _world_size()
        rank = _rank()
        assert out_features % world_size == 0
        self.local_out = out_features // world_size
        start = rank * self.local_out
        end = start + self.local_out
        w = master_weight[start:end, :].clone().detach().contiguous()
        self.weight = nn.Parameter(w)
        if bias:
            self.bias = nn.Parameter(torch.zeros(self.local_out,
                                                 dtype=w.dtype,
                                                 device=w.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, x):
        local_out = F.linear(x, self.weight, self.bias)
        return _AllGatherLastDim.apply(local_out)


class RowParallelLinear(torch.nn.Module):
    def __init__(self, in_features, out_features, bias, master_weight):
        super().__init__()
        self.in_features = in_features
        self.out_features = out_features
        world_size = _world_size()
        rank = _rank()
        assert in_features % world_size == 0
        self.local_in = in_features // world_size
        start = rank * self.local_in
        end = start + self.local_in
        w = master_weight[:, start:end].clone().detach().contiguous()
        self.weight = nn.Parameter(w)
        if bias:
            self.bias = nn.Parameter(torch.zeros(out_features,
                                                 dtype=w.dtype,
                                                 device=w.device))
        else:
            self.register_parameter("bias", None)

    def forward(self, x):
        local_out = F.linear(x, self.weight)
        out = _AllReduce.apply(local_out)
        if self.bias is not None:
            out = out + self.bias
        return out
